from collections import defaultdict
from typing import Callable, Union

def group_by(items: list, key: Union[str, Callable]) -> dict:
    result = defaultdict(list)
    for item in items:
        if callable(key):
            k = key(item)
        else:
            if isinstance(item, dict):
                k = item[key]
            else:
                k = getattr(item, key)
        result[k].append(item)
    return dict(result)
